import { GoogleGenAI } from "@google/genai";
import type { Product } from '../types';
import { imageUrlToBase64 } from "../utils";

const API_KEY = process.env.NEXT_PUBLIC_API_KEY;

if (!API_KEY) {
  console.error("NEXT_PUBLIC_API_KEY not set.");
}

const ai = new GoogleGenAI({ apiKey: API_KEY || "MISSING" });

// --- ИСПРАВЛЕНИЕ: Возвращаем рабочую модель gemini-2.5-pro ---
const model = 'gemini-2.5-pro';

const safeJsonParse = <T>(jsonString: string): T | null => {
    const cleanedString = jsonString.trim().replace(/^```json/, '').replace(/```$/, '').trim();
    try {
        if (typeof cleanedString === 'object') return cleanedString as T;
        return JSON.parse(cleanedString) as T;
    } catch (e) {
        console.error("[safeJsonParse] Failed:", e, "String:", cleanedString);
        return null;
    }
};

// --- Функция теперь возвращает массив чисел (индексов) ---
export const getVisualRecommendations = async (base64Image: string, mimeType: string, products: Product[]): Promise<number[]> => {
  const productList = products.map((p, index) => `${index}: ${p.name}`).join('\n');
  const imagePart = { inlineData: { data: base64Image, mimeType } };
  const textPart = { 
    text: `Проанализируй фото. Вот нумерованный список товаров:\n${productList}\n\nВыбери 3-5 наиболее подходящих товаров. Верни ТОЛЬКО JSON-массив с числами (индексами) из предоставленного списка. Пример: [0, 5, 12]` 
  };

  try {
    const response = await ai.models.generateContent({
        model: model,
        contents: [{ parts: [imagePart, textPart] }],
    });
    const parsed = safeJsonParse<number[]>(response.text);
    return parsed || [];
  } catch (error) {
    console.error('[getVisualRecommendations] CRITICAL ERROR:', error);
    throw error;
  }
};

